const lead = $json;

const SENDER_NAME = 'Ryan'; // <-- EDIT: your name as it should appear in emails
const CALENDLY_URL = 'https://calendly.com/ryan-modernflowai/30min';

const system = `You are ${SENDER_NAME}, founder of ModernFlow AI, a done-for-you AI automation agency for service businesses (contractors, plumbers, HVAC, electricians, roofers, landscapers).\n\nWhat ModernFlow AI does for clients:\n- 24/7 AI assistant that answers calls/texts so missed calls stop turning into lost jobs\n- Automated booking system that fills the calendar without back-and-forth\n- CRM + follow-up automation so no lead ever falls through the cracks\n- Review automation that builds a 5-star reputation on autopilot\n\nWrite a COLD OUTREACH email to the lead described by the user. Rules:\n- 70 to 110 words, plain text, no HTML, no bullet points\n- Personalize the first line to their specific company, trade, and location -- it must NOT feel templated\n- Lead with ONE concrete pain point for their trade (e.g. missed calls during jobs = lost revenue)\n- One soft CTA: offer a free 30-minute strategy call and include this exact link once: ${CALENDLY_URL}\n- No spammy words (free money, guarantee, act now), no exclamation marks, no emojis\n- Subject line: under 6 words, lowercase-casual, specific to them, no clickbait\n- Sign off with just the name ${SENDER_NAME}, ModernFlow AI`;

const userMsg = `Lead:\n- Name: ${lead.first_name} ${lead.last_name}\n- Title: ${lead.title}\n- Company: ${lead.company}\n- Industry: ${lead.industry}\n- Location: ${lead.city}, ${lead.state}\n- Website: ${lead.website}\n\nWrite the outreach email now.`;

return [{
  json: {
    model: 'claude-opus-4-8',
    max_tokens: 2000,
    system,
    messages: [{ role: 'user', content: userMsg }],
    output_config: {
      format: {
        type: 'json_schema',
        schema: {
          type: 'object',
          properties: {
            subject: { type: 'string', description: 'Email subject line' },
            body: { type: 'string', description: 'Plain-text email body including signature' }
          },
          required: ['subject', 'body'],
          additionalProperties: false
        }
      }
    }
  }
}];

const res = $input.first().json;
if (res.stop_reason === 'refusal') {
  throw new Error('Claude declined to write this email — check the lead data.');
}
const textBlock = (res.content || []).find(b => b.type === 'text');
if (!textBlock) throw new Error('No text block in Claude response');
const email = JSON.parse(textBlock.text);
const lead = $('Lead Loop').first().json;
return [{ json: { ...lead, subject: email.subject, body: email.body } }];

const sent = $input.first().json;
const lead = $('Parse Email').first().json;
return [{
  json: {
    email: lead.email,
    status: 'CONTACTED',
    thread_id: sent.threadId || '',
    last_contact_at: new Date().toISOString(),
    notes: 'Outreach sent: ' + lead.subject
  }
}];
